import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            int[] L = new int[N];
            int[] R = new int[N];
            for (int i = 0; i < N; i++) {
                StringTokenizer st = new StringTokenizer(br.readLine());
                L[i] = Integer.parseInt(st.nextToken());
                R[i] = Integer.parseInt(st.nextToken());
            }
            if (N == 1) {
                out.append(1).append('\n').append(1).append('\n');
                continue;
            }
            int[] prefMaxL = new int[N];
            int[] prefMinR = new int[N];
            int[] suffMaxL = new int[N];
            int[] suffMinR = new int[N];
            prefMaxL[0] = L[0];
            prefMinR[0] = R[0];
            for (int i = 1; i < N; i++) {
                prefMaxL[i] = Math.max(prefMaxL[i - 1], L[i]);
                prefMinR[i] = Math.min(prefMinR[i - 1], R[i]);
            }
            suffMaxL[N - 1] = L[N - 1];
            suffMinR[N - 1] = R[N - 1];
            for (int i = N - 2; i >= 0; i--) {
                suffMaxL[i] = Math.max(suffMaxL[i + 1], L[i]);
                suffMinR[i] = Math.min(suffMinR[i + 1], R[i]);
            }
            List<Integer> ans = new ArrayList<>();
            for (int i = 0; i < N; i++) {
                int maxL, minR;
                if (i == 0) {
                    maxL = suffMaxL[1];
                    minR = suffMinR[1];
                } else if (i == N - 1) {
                    maxL = prefMaxL[N - 2];
                    minR = prefMinR[N - 2];
                } else {
                    maxL = Math.max(prefMaxL[i - 1], suffMaxL[i + 1]);
                    minR = Math.min(prefMinR[i - 1], suffMinR[i + 1]);
                }
                int person = i + 1; // 1‑based index
                if (maxL <= minR && person >= maxL && person <= minR) {
                    ans.add(person);
                }
            }
            out.append(ans.size()).append('\n');
            for (int v : ans) {
                out.append(v).append('\n');
            }
        }
        System.out.print(out.toString());
    }
}

